import { RecurringCheckboxConfiguration } from './RecurringCheckboxConfiguration/RecurringCheckboxConfiguration';
import { RecurringUpgrade } from './RecurringUpgrade';

export const Amounts = () => {
  const { t } = useTranslation('actionPagesBuilder');
  const { t: tCommon } = useTranslation('common');
  const { setValue, watch } = useFormContext<ActionPageDetailFormValues>();
  const configurationSelectorProps = useAmountConfigurations();
  const amountPresetsByFrequency = watch('amountConfiguration.amountPresets');

  const amountPresetsLoaded = Boolean(amountPresetsByFrequency);
  const amountPresetsOther = watch('amountConfiguration.amountPresetsOther');
  const recurringOptions = watch('amountConfiguration.recurringOptions');
  const defaultPresets = useMemo(
    () => [
      { amount: 25, description: '', id: v4() },
      { amount: 50, description: '', id: v4() },
      { amount: 100, description: '', id: v4() },
      { amount: 200, description: '', id: v4() },
    ],
    []
  ) as ActionPageAmountPreset[];
  const [selectedFrequency, setSelectedFrequency] = useState<AmountPresetFrequency | 'default'>(
    'default'
  );
  // Campaign Parity: users can now disable both Amount Presets and Other Amount,
  // allowing entry of custom amounts for each fund with no allocation limitations.
  const hasRecurringPresets =
    recurringOptions?.some(
      (option) => (amountPresetsByFrequency?.[option as AmountPresetFrequency] ?? []).length > 0
    ) ?? false;
  const hasDefaultPresets = (amountPresetsByFrequency?.default ?? []).length > 0;
  const hasAnyPresets = hasRecurringPresets || hasDefaultPresets;
  const isCampaignParity = !hasAnyPresets && !amountPresetsOther;
  const isLoaded = amountPresetsLoaded && !configurationSelectorProps?.isLoading;
  const frequencyOptions = useMemo(
    () => [
      {
        value: 'default',
        label: 'All Frequencies',
      },
      ...(recurringOptions?.map((opt) => ({
        label: tCommon(`frequency.recurring.${opt}`),
        value: opt.toString(),
      })) ?? []),
    ],
    [recurringOptions, tCommon]
  );
  const activeFrequency = recurringOptions?.includes(selectedFrequency as SourceFrequency)
    ? (selectedFrequency as SourceFrequency)
    : 'default';
  const amountPresetsPath = activeFrequency
    ? (`amountConfiguration.amountPresets.${activeFrequency}` as const)
    : undefined;

  useEffect(() => {
    if (!recurringOptions?.length) {
      setSelectedFrequency('default');
      return;
    }

    // if we deleted the currently selected frequency, go back to default
    if (
      !recurringOptions.includes(selectedFrequency as SourceFrequency) &&
      selectedFrequency !== 'default'
    ) {
      setSelectedFrequency('default');
    }
  }, [recurringOptions, selectedFrequency]);

  const setFrequencyPresetsToDefault = useCallback(
    (frequencyKey: AmountPresetFrequency) => {
      let defaultsForPreset = defaultPresets;
      if (hasDefaultPresets && amountPresetsByFrequency && amountPresetsByFrequency.default) {
        defaultsForPreset = amountPresetsByFrequency.default;
      }
      setValue(
        `amountConfiguration.amountPresets.${frequencyKey}`,
        defaultsForPreset.map((preset) => ({ ...preset }))
      );
    },
    [defaultPresets, setValue, amountPresetsByFrequency, hasDefaultPresets]
  );

  const setRecurringPresetsToDefault = useCallback(() => {
    if (!amountPresetsByFrequency || !recurringOptions) {
      return;
    }
    recurringOptions.forEach((key) => {
      const frequencyKey = key as AmountPresetFrequency;
      const presets = amountPresetsByFrequency?.[frequencyKey];
      if (presets == null || presets.length === 0) {
        // NOTE: we need to map here to get a full clone of the presets
        setFrequencyPresetsToDefault(frequencyKey);
      }
    });
  }, [recurringOptions, amountPresetsByFrequency, setFrequencyPresetsToDefault]);

  // if we have selected default and there are presets already set for other
  // frequencies, show the button that will wipe out those presets
  const showApplyToAllButton = useMemo(() => {
    if (selectedFrequency !== 'default') {
      return false;
    }

    if (amountPresetsByFrequency) {
      return Object.entries(amountPresetsByFrequency).some(([key, value]) => {
        return key !== 'default' && value.length > 0;
      });
    }
  }, [amountPresetsByFrequency, selectedFrequency]);

  const handleAddFrequency = useCallback(
    (addedFrequency: SourceFrequency) => {
      // Check if we should fill int he new frequency with defaults
      if (hasRecurringPresets) {
        setFrequencyPresetsToDefault(addedFrequency);
      }
    },
    [setFrequencyPresetsToDefault, hasRecurringPresets]
  );

  return (
    <ConfigurationPanel {...configurationSelectorProps}>
      <Stack spacing={6}>
        {!isCampaignParity && (
          <Skeleton isLoaded={isLoaded}>
            <FrequencyOptions onAddFrequency={handleAddFrequency} />
          </Skeleton>
        )}

        <Stack spacing={6}>
          <Flex flexDirection="column" gap={1}>
            <Label variant="medium">{t('amountsPanel.amountsConfiguration')}</Label>
            <Label color="neutral.400" variant="medium">
              {t('amountsPanel.description')}
            </Label>
          </Flex>
        </Stack>
        <Skeleton isLoaded={isLoaded}>
          <Stack>
            {frequencyOptions.length > 0 ? (
              <Stack spacing={2}>
                <Label variant="medium">{tCommon('frequency.title')}</Label>
                <SelectControl
                  name="amountPresetsFrequency"
                  onChange={(event) => {
                    const frequencyKey = event.target.value as AmountPresetFrequency;
                    setSelectedFrequency(frequencyKey);

                    if (frequencyKey !== 'default' && !hasRecurringPresets && hasDefaultPresets) {
                      // Presets are either set individually (all keys are
                      // preset on amount presets) or all set at once via
                      // default (no other key are preset)
                      //
                      // Here we are switching from default mode to
                      // individual presets mode by initializing all keys to
                      // default
                      setRecurringPresetsToDefault();
                    }
                  }}
                  options={frequencyOptions}
                  value={activeFrequency ?? ''}
                  variant="outline"
                />
              </Stack>
            ) : null}
            {amountPresetsPath && activeFrequency ? (
              <FieldArray key={amountPresetsPath} name={amountPresetsPath}>
                {({ append, fields, move, remove }) => (
                  <>
                    <DragDrop
                      id={`amountPresets.${activeFrequency}`}
                      onDragEnd={({ destination, source }) => {
                        if (destination) {
                          move(source.index, destination?.index);
                        }
                      }}
                    >
                      {fields.map((field, index) => {
                        return (
                          <DragDrop.Item id={field.id} index={index} key={field.id} py={1}>
                            <AmountPresetItem
                              inputLeftLabel={t('designer.finance.amounts.amount')}
                              inputLeftName={`${amountPresetsPath}.${index}.amount`}
                              inputRightLabel={t('designer.finance.amounts.descriptionOptional')}
                              inputRightName={`${amountPresetsPath}.${index}.description`}
                              onDelete={() => {
                                remove(index);
                              }}
                            />
                          </DragDrop.Item>
                        );
                      })}
                    </DragDrop>
                    {showApplyToAllButton && (
                      <Button
                        onClick={() => {
                          // Presets are either set individually (all keys are
                          // preset on amount presets) or all set at once via
                          // default (no other key are preset)
                          //
                          // Here we are switching from individual mode to
                          // default mode by clearing all keys but default
                          let defaultsForPreset = defaultPresets;
                          if (amountPresetsByFrequency && amountPresetsByFrequency.default) {
                            defaultsForPreset = amountPresetsByFrequency.default;
                          }
                          setValue(`amountConfiguration.amountPresets`, {
                            default: defaultsForPreset.map((preset) => ({ ...preset })),
                          });
                        }}
                      >
                        Apply to All Frequencies
                      </Button>
                    )}
                    {!fields || fields.length === 0 ? (
                      <Button
                        mt={1}
                        onClick={() => {
                          setFrequencyPresetsToDefault(activeFrequency);
                          // If there are no presets on any of the frequencies
                          // we assume this is the first time they've enabled
                          // presets and we should set defaults for ALL
                          // frequencies, otherwise just populate defaults for
                          // the selected frequency
                          // => This happens when you switch defaults from "All
                          // Frequencies" to an individual preset before
                          // enabling presets
                          if (!hasRecurringPresets && activeFrequency !== 'default') {
                            setRecurringPresetsToDefault();
                          }
                          // also set "All Frequencies" to default if not
                          // already set
                          if (!hasDefaultPresets || activeFrequency === 'default') {
                            setFrequencyPresetsToDefault('default');
                          }
                        }}
                        variant="secondary"
                      >
                        {t('designer.finance.amounts.enablePresets')}
                      </Button>
                    ) : (
                      <Button
                        leftIcon={<AddIcon />}
                        mt={1}
                        onClick={() => {
                          setValue('amountConfiguration.recurringEnabled', true);
                          // todo: figure out how to do this the "other" way
                          append({
                            amount: '',
                            description: '',
                            id: v4(),
                          });
                        }}
                        variant="secondary"
                      >
                        {t('designer.finance.amounts.addAmount')}
                      </Button>
                    )}
                  </>
                )}
              </FieldArray>
            ) : (
              <Button
                onClick={() => setValue('amountConfiguration.recurringEnabled', true)}
                variant="secondary"
              >
                {t('designer.finance.amounts.enablePresets')}
              </Button>
            )}
          </Stack>
        </Skeleton>
        {/* <Stack>
                <Label variant="bold">{t('designer.finance.amounts.defaultAmount')}</Label>
                <Meta variant="regular">{t('designer.finance.amounts.defaultAmountSubtitle')}</Meta>
                <SelectControl
